import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import { generateResumePDF } from '../server/generators/resumePDF.js';
import { generateCoverLetterPDF } from '../server/generators/coverLetterPDF.js';
import { generateInfographic } from '../server/generators/infographic.js';

const SAMPLE_RESUME = [
  '# Jane Doe',
  '## Summary',
  'Backend engineer with 5 years of Node.js experience.',
  '## Experience',
  '### Senior Engineer — Acme Corp (2021–present)',
  '- Built APIs serving 10M requests/day',
  '- Led team of four engineers',
  '## Skills',
  '**Languages**: JavaScript, TypeScript',
  '---',
  '## Education',
  'B.S. Computer Science — State University, 2019',
].join('\n');

const SAMPLE_LETTER = [
  'Dear Hiring Manager,',
  '',
  'I am excited to apply for the Senior Engineer position.',
  '',
  '**Key achievement**: Reduced latency by 40%.',
  '',
  'Sincerely,',
  'Jane Doe',
].join('\n');

// ---------------------------------------------------------------------------
// generateResumePDF
// ---------------------------------------------------------------------------

describe('generateResumePDF', () => {
  it('returns a Buffer', async () => {
    const buf = await generateResumePDF(SAMPLE_RESUME);
    assert.ok(buf instanceof Buffer);
  });

  it('output starts with PDF magic bytes %PDF', async () => {
    const buf = await generateResumePDF(SAMPLE_RESUME);
    assert.equal(buf.slice(0, 4).toString(), '%PDF');
  });

  it('produces a non-trivially-sized output', async () => {
    const buf = await generateResumePDF(SAMPLE_RESUME);
    assert.ok(buf.length > 500, `expected > 500 bytes, got ${buf.length}`);
  });

  it('handles markdown headings and bullet points without throwing', async () => {
    const text = '# Title\n## Section\n- Item one\n- Item two\n### Sub\n**Bold** text';
    const buf = await generateResumePDF(text);
    assert.equal(buf.slice(0, 4).toString(), '%PDF');
  });

  it('handles a horizontal rule line', async () => {
    const buf = await generateResumePDF('Header\n---\nBody');
    assert.equal(buf.slice(0, 4).toString(), '%PDF');
  });

  it('handles minimal single-line input', async () => {
    const buf = await generateResumePDF('Jane Doe');
    assert.equal(buf.slice(0, 4).toString(), '%PDF');
  });
});

