// ---------------------------------------------------------------------------
// generateInfographic
// ---------------------------------------------------------------------------

describe('generateInfographic', () => {
  it('returns a string', () => {
    const svg = generateInfographic({ pros: ['Good culture'], cons: ['Long hours'] });
    assert.equal(typeof svg, 'string');
  });

  it('starts with an XML declaration', () => {
    const svg = generateInfographic({ pros: ['Good culture'], cons: ['Long hours'] });
    assert.ok(svg.startsWith('<?xml'), 'expected <?xml declaration');
  });

  it('contains an <svg> element', () => {
    const svg = generateInfographic({ pros: ['Good culture'], cons: ['Long hours'] });
    assert.ok(svg.includes('<svg '));
  });

  it('includes pros and cons text in the output', () => {
    const svg = generateInfographic({
      pros: ['Remote work', 'Strong benefits'],
      cons: ['Long hours', 'High pressure'],
    });
    assert.ok(svg.includes('Remote work'));
    assert.ok(svg.includes('Long hours'));
    assert.ok(svg.includes('Pros'));
    assert.ok(svg.includes('Cons'));
  });

  it('escapes XML special characters', () => {
    const svg = generateInfographic({
      pros: ['Salary > $100k'],
      cons: ['Uses <legacy> code & old tools'],
    });
    assert.ok(!svg.includes('</legacy>'), 'unescaped < should not appear');
    assert.ok(svg.includes('&lt;'), 'expected &lt; escape');
    assert.ok(svg.includes('&amp;'), 'expected &amp; escape');
  });

  it('handles empty arrays without throwing', () => {
    assert.doesNotThrow(() => generateInfographic({ pros: [], cons: [] }));
    const svg = generateInfographic({ pros: [], cons: [] });
    assert.ok(svg.includes('<svg '));
  });

  it('defaults missing keys to empty arrays', () => {
    assert.doesNotThrow(() => generateInfographic({}));
    const svg = generateInfographic({});
    assert.ok(svg.includes('<svg '));
  });

  it('word-wraps long text without throwing', () => {
    const longPro = 'This is a very long pro statement that should be wrapped across multiple lines in the SVG output';
    const svg = generateInfographic({ pros: [longPro], cons: [] });
    assert.ok(svg.includes('<svg '));
  });
});
